/* ═══════════════════════════════════════════════
   PIXEL GALLERY — JavaScript
   ═══════════════════════════════════════════════ */

import PocketBase from 'https://cdn.jsdelivr.net/npm/pocketbase/dist/pocketbase.es.mjs';

const pb = new PocketBase('http://207.127.92.120:8090/');

// ═══════════════════════════════════════════════
//  REACTIONS CONFIG
// ═══════════════════════════════════════════════
const REACTIONS = [
  { type: 'adorbs',  label: 'Adorbs',  img: 'data:image/png;base64,' },
  { type: 'swag',    label: 'Swag',    img: 'data:image/png;base64,' },
  { type: 'magical', label: 'Magical', img: 'data:image/png;base64,' },
];

function getVoted(drawingId) {
  try { return JSON.parse(localStorage.getItem('voted_' + drawingId) || '[]'); }
  catch { return []; }
}
function saveVoted(drawingId, voted) {
  localStorage.setItem('voted_' + drawingId, JSON.stringify(voted));
}

// ═══════════════════════════════════════════════
//  STATE
// ═══════════════════════════════════════════════
let gallery        = [];
let filtered       = [];
let currentFilter  = 'all';
let lightboxIdx    = -1;
let reactionCounts = {}; // { drawingId: { adorbs: 3, swag: 1 ... } }

// ═══════════════════════════════════════════════
//  LOAD FROM POCKETBASE
// ═══════════════════════════════════════════════
async function loadGallery() {
  try {
    const result = await pb.collection('drawings').getList(1, 200, { sort: '-created' });
    gallery = result.items.map(record => ({
      id:       record.id,
      title:    record.title,
      label:    record.label,
      time:     new Date(record.created).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      imageUrl: pb.files.getURL(record, record.image),
    }));
  } catch (err) {
    console.error('Failed to load gallery:', err);
    gallery = [];
  }
  await loadAllReactions();
  applyFilter(currentFilter);
}

// ═══════════════════════════════════════════════
//  REACTIONS — LOAD ALL COUNTS FROM SERVER
// ═══════════════════════════════════════════════
async function loadAllReactions() {
  try {
    // fetch all reaction records (up to 2000)
    const result = await pb.collection('reactions').getList(1, 2000, {});
    reactionCounts = {};
    result.items.forEach(r => {
      const id = r.drawing; // this is the related drawing's ID string
      if (!reactionCounts[id]) reactionCounts[id] = {};
      reactionCounts[id][r.type] = (reactionCounts[id][r.type] || 0) + 1;
    });
  } catch (err) {
    console.error('Failed to load reactions:', err);
  }
}

// fetch fresh counts for ONE drawing from server and update state
async function refreshCountsForDrawing(drawingId) {
  try {
    const result = await pb.collection('reactions').getList(1, 500, {
      filter: 'drawing = "' + drawingId + '"',
    });
    const counts = {};
    result.items.forEach(r => {
      counts[r.type] = (counts[r.type] || 0) + 1;
    });
    reactionCounts[drawingId] = counts;
  } catch (err) {
    console.error('Failed to refresh counts:', err);
  }
}

// ═══════════════════════════════════════════════
//  REACTIONS — ADD
// ═══════════════════════════════════════════════
async function addReaction(drawingId, type) {
  const voted = getVoted(drawingId);
  if (voted.includes(type)) return;

  try {
    await pb.collection('reactions').create({ drawing: drawingId, type });
    // save voted state immediately
    voted.push(type);
    saveVoted(drawingId, voted);
    // fetch fresh counts from server so number is accurate
    await refreshCountsForDrawing(drawingId);
    // re-render all bars for this drawing
    refreshReactionBars(drawingId);
  } catch (err) {
    console.error('Failed to add reaction:', err);
  }
}

// ═══════════════════════════════════════════════
//  REACTIONS — BUILD BAR
// ═══════════════════════════════════════════════
function buildReactionBar(drawingId, compact) {
  const voted   = getVoted(drawingId);
  const counts  = reactionCounts[drawingId] || {};
  const wrapper = document.createElement('div');
  wrapper.className = compact ? 'reaction-bar reaction-bar--compact' : 'reaction-bar';
  wrapper.dataset.drawingId = drawingId;

  REACTIONS.forEach(r => {
    const hasVoted = voted.includes(r.type);
    const count    = counts[r.type] || 0;
    const btn      = document.createElement('button');
    btn.className  = 'reaction-btn' + (hasVoted ? ' voted' : '');
    btn.dataset.type = r.type;
    btn.innerHTML  =
      '<img class="r-img" src="' + r.img + '" alt="' + r.label + '"/>' +
      '<span class="r-label">' + r.label + '</span>' +
      '<span class="r-count">' + count + '</span>';
    btn.addEventListener('click', async (e) => {
      e.stopPropagation();
      await addReaction(drawingId, r.type);
    });
    wrapper.appendChild(btn);
  });
  return wrapper;
}

function refreshReactionBars(drawingId) {
  document.querySelectorAll('.reaction-bar[data-drawing-id="' + drawingId + '"]').forEach(bar => {
    const compact = bar.classList.contains('reaction-bar--compact');
    const oldId   = bar.id;
    const newBar  = buildReactionBar(drawingId, compact);
    if (oldId) newBar.id = oldId;
    bar.replaceWith(newBar);
  });
}

// ═══════════════════════════════════════════════
//  FILTER
// ═══════════════════════════════════════════════
function filterBy(label, btn) {
  currentFilter = label;
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  applyFilter(label);
}

function applyFilter(label) {
  filtered = label === 'all'
    ? [...gallery]
    : gallery.filter(g => g.label === label);
  renderGallery();
}

// ═══════════════════════════════════════════════
//  RENDER GALLERY
// ═══════════════════════════════════════════════
function renderGallery() {
  const grid = document.getElementById('galGrid');
  const n    = gallery.length;
  document.getElementById('headerCount').textContent = n + ' sprite' + (n !== 1 ? 's' : '');

  if (!filtered.length) {
    grid.innerHTML =
      '<div class="gallery-empty">' +
      '<span class="big">[ EMPTY ]</span>' +
      (currentFilter === 'all'
        ? 'No sprites yet. Draw something in the Studio!'
        : 'No ' + currentFilter + ' sprites yet.') +
      '</div>';
    return;
  }

  grid.innerHTML = '';
  filtered.forEach((item, fi) => {
    const card = document.createElement('div');
    card.className = 'card';

    const imgWrap = document.createElement('div');
    imgWrap.className = 'card-img-wrap';
    imgWrap.innerHTML = '<img src="' + item.imageUrl + '" alt="' + (item.label || 'sprite') + '"/>';
    imgWrap.addEventListener('click', () => openLightbox(fi));

    const footer = document.createElement('div');
    footer.className = 'card-footer';
    footer.innerHTML =
      '<div class="card-meta">' +
        '<div class="card-title">' + (item.label || '?x?') + '</div>' +
        '<div class="card-info">' + item.time + '</div>' +
      '</div>';

    card.appendChild(imgWrap);
    card.appendChild(footer);
    card.appendChild(buildReactionBar(item.id, true));
    grid.appendChild(card);
  });
}

// ═══════════════════════════════════════════════
//  LIGHTBOX
// ═══════════════════════════════════════════════
function openLightbox(fi) {
  lightboxIdx = fi;
  const item  = filtered[fi];
  document.getElementById('lbImg').src        = item.imageUrl;
  document.getElementById('lbMeta').innerHTML = '<span>' + (item.label || '?') + '</span> &middot; ' + item.time;

  // rebuild reaction bar for this image
  const existing = document.getElementById('lbReactions');
  const bar = buildReactionBar(item.id, false);
  bar.id    = 'lbReactions';
  if (existing) {
    existing.replaceWith(bar);
  } else {
    document.querySelector('.lb-inner').appendChild(bar);
  }

  document.getElementById('lightbox').classList.add('open');
}

function closeLightbox() {
  document.getElementById('lightbox').classList.remove('open');
  lightboxIdx = -1;
}

function showNext() {
  if (lightboxIdx < 0) return;
  openLightbox(Math.min(lightboxIdx + 1, filtered.length - 1));
}

function showPrev() {
  if (lightboxIdx < 0) return;
  openLightbox(Math.max(lightboxIdx - 1, 0));
}

// ═══════════════════════════════════════════════
//  KEYBOARD
// ═══════════════════════════════════════════════
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') closeLightbox();
  if (e.key === 'ArrowRight' && lightboxIdx >= 0)
    openLightbox(Math.min(lightboxIdx + 1, filtered.length - 1));
  if (e.key === 'ArrowLeft' && lightboxIdx >= 0)
    openLightbox(Math.max(lightboxIdx - 1, 0));
});

document.getElementById('lightbox').addEventListener('click', e => {
  if (e.target === document.getElementById('lightbox')) closeLightbox();
});

// ═══════════════════════════════════════════════
//  WIRE UP BUTTONS
// ═══════════════════════════════════════════════
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.filter-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const raw   = btn.textContent.trim();
      const label = raw === 'ALL' ? 'all' : raw;
      filterBy(label, btn);
    });
  });
  document.getElementById('btnCloseLightbox')?.addEventListener('click', closeLightbox);
  document.getElementById('btnNext')?.addEventListener('click', showNext);
  document.getElementById('btnPrev')?.addEventListener('click', showPrev);
  document.getElementById('btnCancelClear')?.addEventListener('click', () => {
    document.getElementById('clearModal').classList.remove('open');
  });
});

// ═══════════════════════════════════════════════
//  BOOT
// ═══════════════════════════════════════════════
loadGallery();
